-- Оновлення описів існуючих костюмів на більш професійні
UPDATE costumes 
SET description = 'Ексклюзивний комплект лицарських обладунків, виготовлений за кресленнями майстрів 15-го століття. Включає кірасу, наплічники, поножі та автентичний шолом. Ідеально підходить для історичних реконструкцій, театральних постановок та тематичних фотосесій. Матеріал: полегшений сплав, що імітує сталь, для комфортного носіння протягом усього дня.'
WHERE name = 'Лицарський обладунок';

UPDATE costumes 
SET description = 'Витончений костюм ельфійського слідопита. Включає довгий плащ глибокого лісового зеленого кольору з вишивкою ручної роботи, шкіряну туніку, імітацію ельфійського лука з різьбленням та сагайдак зі стрілами. Матеріали преміум-класу забезпечують дихаючі властивості та зручність рухів. Створений для поціновувачів високого фентезі.'
WHERE name = 'Костюм ельфа';

UPDATE costumes 
SET description = 'Професійний косплей-костюм Темного Лицаря. Виготовлений з високотехнологічних еластичних матеріалів з текстурою кевлару. Включає анатомічний нагрудник, важкий плащ з еко-шкіри, який ефектно розлітається при русі, та деталізовану маску з ефектом тонування очей. Ідеальний вибір для Comic-Con, тематичних вечірок та аніматорів.'
WHERE name = 'Бетмен';

UPDATE costumes 
SET description = 'Вампірський плащ преміум-якості з високим жорстким коміром-стійкою. Зовнішня сторона виконана з матового чорного оксамиту, а підкладка — з червоного атласу, який створює розкішний контраст. Застібається на елегантний металевий ланцюжок. Додає образу містичності та аристократизму.'
WHERE name = 'Вампірський плащ';

UPDATE costumes 
SET description = 'Класичний піратський капелюх-треуголка з широкими крисами, оздоблений справжнім страусиним пером та золотою тасьмою. Жорсткий фетр чудово тримає форму.'
WHERE name = 'Піратський капелюх';

UPDATE costumes 
SET description = 'Автентична венеціанська напівмаска "Коломбіна", оздоблена чорним мереживом та кристалами. Зручно кріпиться за допомогою шовкових стрічок.'
WHERE name = 'Маска Зорро';

UPDATE costumes 
SET description = 'Елегантний червоний плащ до підлоги з глибоким капюшоном. Виконаний з важкого струмуючого оксамиту. Універсальний аксесуар для створення образів чаклунки, Червоної Шапочки або таємничої незнайомки.'
WHERE name = 'Червоний плащ';


